import java.util.*; import java.util.stream.*;
public class EmployeeSalaryStreamSort { static class Employee { String name; double salary; Employee(String name, double salary) { this.name = name; this.salary = salary; } public String toString() { return name + " " + salary; } } public static void main(String[] args) { List<Employee> employees = Arrays.asList(new Employee("Asha", 50000), new Employee("Bala", 45000), new Employee("Charu", 60000)); List<Employee> sorted = employees.stream().sorted(Comparator.comparingDouble(e -> e.salary)).collect(Collectors.toList()); System.out.println(sorted); } }
